+@preconcurrency import ApplicationServices
+import AppKit
+import Foundation
+
+protocol ActivationObserving: AnyObject {
+    func invalidate()
+}
+
+protocol ApplicationActivationNotifying {
+    func observe(_ handler: @escaping @Sendable (FrontmostApplicationContext?) -> Void) -> any ActivationObserving
+}
+
+enum AccessibilityObserverNotification: Equatable {
+    case focusedElementChanged
+    case focusedWindowChanged
+    case other(String)
+}
+
+struct AccessibilityObserverEvent {
+    let processID: pid_t
+    let notification: AccessibilityObserverNotification
+    let element: (any AccessibilityElement)?
+}
+
+protocol ProcessAccessibilityObserving: AnyObject {
+    func invalidate()
+}
+
+protocol AccessibilityObserverCreating {
+    func make(
+        processID: pid_t,
+        handler: @escaping (AccessibilityObserverEvent) -> Void
+    ) -> (any ProcessAccessibilityObserving)?
+}
+
+final class ContinuousPasteTargetMonitor: PasteTargetMonitoring, @unchecked Sendable {
+    static let shared = ContinuousPasteTargetMonitor()
+
+    var currentObservation: PasteTargetObservation?
+
+    private let activationNotifier: any ApplicationActivationNotifying
+    private let observerFactory: any AccessibilityObserverCreating
+    private let evaluator = AccessibilityPasteTargetEvaluator()
+
+    private var activationObservation: (any ActivationObserving)?
+    private var observedProcessID: pid_t?
+    private var observer: (any ProcessAccessibilityObserving)?
+    private var isStarted = false
+
+    init(
+        activationNotifier: any ApplicationActivationNotifying = WorkspaceActivationNotifier(),
+        observerFactory: any AccessibilityObserverCreating = AXAccessibilityObserverFactory()
+    ) {
+        self.activationNotifier = activationNotifier
+        self.observerFactory = observerFactory
+    }
+
+    func start() {
+        guard !isStarted else {
+            return
+        }
+
+        isStarted = true
+        activationObservation = activationNotifier.observe { [weak self] application in
+            self?.synchronize(to: application)
+        }
+    }
+
+    func synchronize(to application: FrontmostApplicationContext?) {
+        let nextProcessID = application?.processID
+        guard observedProcessID != nextProcessID else {
+            return
+        }
+
+        observer?.invalidate()
+        observer = nil
+        observedProcessID = nextProcessID
+        clearObservation()
+
+        guard let nextProcessID else {
+            return
+        }
+
+        observer = observerFactory.make(processID: nextProcessID) { [weak self] event in
+            self?.handle(event)
+        }
+    }
+
+    func record(_ observation: PasteTargetObservation) {
+        currentObservation = observation
+    }
+
+    func clearObservation() {
+        currentObservation = nil
+    }
+
+    private func handle(_ event: AccessibilityObserverEvent) {
+        guard
+            let element = event.element,
+            event.notification == .focusedElementChanged || event.notification == .focusedWindowChanged
+        else {
+            return
+        }
+
+        let isEditable = evaluator.findPasteTarget(
+            startingAt: element,
+            focusContext: event.notification == .focusedElementChanged
+        ) != nil
+
+        currentObservation = PasteTargetObservation(
+            processID: event.processID,
+            windowID: element.windowID,
+            status: isEditable ? .editable : .nonEditable
+        )
+    }
+}
+
+struct WorkspaceActivationNotifier: ApplicationActivationNotifying {
+    func observe(_ handler: @escaping @Sendable (FrontmostApplicationContext?) -> Void) -> any ActivationObserving {
+        let center = NSWorkspace.shared.notificationCenter
+        let token = center.addObserver(
+            forName: NSWorkspace.didActivateApplicationNotification,
+            object: nil,
+            queue: nil
+        ) { notification in
+            let application = notification.userInfo?[NSWorkspace.applicationUserInfoKey] as? NSRunningApplication
+            handler(
+                application.map {
+                    FrontmostApplicationContext(
+                        processID: $0.processIdentifier,
+                        bundleIdentifier: $0.bundleIdentifier
+                    )
+                }
+            )
+        }
+
+        return NotificationCenterActivationObservation(center: center, token: token)
+    }
+}
+
+private final class NotificationCenterActivationObservation: ActivationObserving {
+    private let center: NotificationCenter
+    private var token: NSObjectProtocol?
+
+    init(center: NotificationCenter, token: NSObjectProtocol) {
+        self.center = center
+        self.token = token
+    }
+
+    func invalidate() {
+        guard let token else {
+            return
+        }
+
+        center.removeObserver(token)
+        self.token = nil
+    }
+}
+
+struct AXAccessibilityObserverFactory: AccessibilityObserverCreating {
+    func make(
+        processID: pid_t,
+        handler: @escaping (AccessibilityObserverEvent) -> Void
+    ) -> (any ProcessAccessibilityObserving)? {
+        AXProcessAccessibilityObserver(processID: processID, handler: handler)
+    }
+}
+
+private final class AXProcessAccessibilityObserver: ProcessAccessibilityObserving {
+    private let processID: pid_t
+    private let observer: AXObserver
+    private let applicationElement: AXUIElement
+    private let handler: (AccessibilityObserverEvent) -> Void
+    private let runLoop: CFRunLoop
+
+    private init(
+        processID: pid_t,
+        observer: AXObserver,
+        applicationElement: AXUIElement,
+        runLoop: CFRunLoop,
+        handler: @escaping (AccessibilityObserverEvent) -> Void
+    ) {
+        self.processID = processID
+        self.observer = observer
+        self.applicationElement = applicationElement
+        self.handler = handler
+        self.runLoop = runLoop
+    }
+
+    convenience init?(
+        processID: pid_t,
+        runLoop: CFRunLoop = CFRunLoopGetMain(),
+        handler: @escaping (AccessibilityObserverEvent) -> Void
+    ) {
+        var rawObserver: AXObserver?
+        let callback: AXObserverCallback = { _, element, notification, userInfo in
+            guard let userInfo else {
+                return
+            }
+
+            let observer = Unmanaged<AXProcessAccessibilityObserver>.fromOpaque(userInfo).takeUnretainedValue()
+            observer.handle(element: element, notification: notification as String)
+        }
+
+        guard AXObserverCreate(processID, callback, &rawObserver) == .success, let rawObserver else {
+            return nil
+        }
+
+        let applicationElement = AXUIElementCreateApplication(processID)
+        self.init(
+            processID: processID,
+            observer: rawObserver,
+            applicationElement: applicationElement,
+            runLoop: runLoop,
+            handler: handler
+        )
+
+        guard install() else {
+            return nil
+        }
+    }
+
+    func invalidate() {
+        AXObserverRemoveNotification(observer, applicationElement, kAXFocusedUIElementChangedNotification as CFString)
+        AXObserverRemoveNotification(observer, applicationElement, kAXFocusedWindowChangedNotification as CFString)
+        CFRunLoopRemoveSource(runLoop, AXObserverGetRunLoopSource(observer), .commonModes)
+    }
+
+    private func install() -> Bool {
+        _ = AXUIElementSetAttributeValue(applicationElement, "AXEnhancedUserInterface" as CFString, kCFBooleanTrue)
+
+        let userInfo = UnsafeMutableRawPointer(Unmanaged.passUnretained(self).toOpaque())
+        let focusedElementResult = AXObserverAddNotification(
+            observer,
+            applicationElement,
+            kAXFocusedUIElementChangedNotification as CFString,
+            userInfo
+        )
+        let focusedWindowResult = AXObserverAddNotification(
+            observer,
+            applicationElement,
+            kAXFocusedWindowChangedNotification as CFString,
+            userInfo
+        )
+
+        guard focusedElementResult == .success, focusedWindowResult == .success else {
+            if focusedElementResult == .success {
+                AXObserverRemoveNotification(observer, applicationElement, kAXFocusedUIElementChangedNotification as CFString)
+            }
+            if focusedWindowResult == .success {
+                AXObserverRemoveNotification(observer, applicationElement, kAXFocusedWindowChangedNotification as CFString)
+            }
+            return false
+        }
+
+        CFRunLoopAddSource(runLoop, AXObserverGetRunLoopSource(observer), .commonModes)
+        return true
+    }
+
+    private func handle(element: AXUIElement, notification: String) {
+        handler(
+            AccessibilityObserverEvent(
+                processID: processID,
+                notification: mapNotification(notification),
+                element: AXAccessibilityElement(element: element)
+            )
+        )
+    }
+
+    private func mapNotification(_ notification: String) -> AccessibilityObserverNotification {
+        if notification == kAXFocusedUIElementChangedNotification as String {
+            return .focusedElementChanged
+        }
+
+        if notification == kAXFocusedWindowChangedNotification as String {
+            return .focusedWindowChanged
+        }
+
+        return .other(notification)
+    }
+}
